```suggestion
    m_probe = nullptr;
    probe.m_monitor = nullptr;
    auto on_cancel = std::move(m_on_cancel);
    if (on_cancel) on_cancel();
```

NIT; possible UAF issues ?   if on-cancel callback destroys CancelMonitor. Solve it by applying a move-out-before-use style pattern. 

Test to show issues: 

<details>

extension to src/ipc/libmultiprocess/test/mp/test/test.cpp

```c++
KJ_TEST("CancelMonitor detaches probe before callback")
{
    CancelMonitor monitor;
    CancelProbe* probe_ptr{nullptr};
    bool detached_before_callback{false};
    monitor.m_on_cancel = [&] {
        detached_before_callback = monitor.m_probe == nullptr && probe_ptr && probe_ptr->m_monitor == nullptr;
    };

    {
        CancelProbe probe(monitor);
        probe_ptr = &probe;
    }

    KJ_EXPECT(detached_before_callback);
    KJ_EXPECT(monitor.m_canceled);
    KJ_EXPECT(monitor.m_probe == nullptr);
}

KJ_TEST("CancelMonitor callback may destroy monitor")
{
    auto monitor = std::make_unique<CancelMonitor>();
    bool callback_called{false};
    monitor->m_on_cancel = [&] {
        callback_called = true;
        monitor.reset();
    };

    {
        CancelProbe probe(*monitor);
    }

    KJ_EXPECT(callback_called);
    KJ_EXPECT(monitor == nullptr);
}
```

